function MetricCard({ target, unit, label, note, isNum }) {
  const [ref, vis] = useInView(0.5);
  const val = useCounter(isNum ? target : 0, vis && isNum);
  return (
    <div ref={ref} style={{ padding:"52px 36px",textAlign:"center",borderRight:"1px solid rgba(255,255,255,.07)",position:"relative",overflow:"hidden" }}
      onMouseEnter={e=>e.currentTarget.querySelector(".mb")?.style && (e.currentTarget.style.background="rgba(0,229,137,.06)")}
      onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
      <div className="mb" style={{ fontFamily:"'Syne',sans-serif",fontSize:68,fontWeight:800,color:VOLT,lineHeight:1,letterSpacing:"-.04em" }}>
        {isNum ? val : target}<span style={{ fontSize:34,opacity:.6 }}>{unit}</span>
      </div>
      <div style={{ fontSize:13,color:SMOKE,marginTop:14,lineHeight:1.45 }} dangerouslySetInnerHTML={{__html:label}}/>
      <div style={{ fontFamily:"'Martian Mono',monospace",fontSize:9,color:"rgba(0,229,137,.4)",marginTop:8,letterSpacing:".1em" }}>{note}</div>
    </div>
  );
}
